function solve(s) {
    const segments = [];
    const seen = new Set();
    let currentSegment = '';
    let i = 0;
    while (i < s.length) {
        currentSegment += s[i];
        if (!seen.has(currentSegment)) {
            seen.add(currentSegment);
            segments.push(currentSegment);
            currentSegment = '';
        } else {
            i++;
        }
    }
    return segments;
}
